
CREATE TABLE public.seo_locations (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  slug text NOT NULL UNIQUE,
  location_name text NOT NULL,
  h1 text NOT NULL,
  seo_title text NOT NULL,
  seo_description text NOT NULL,
  intro_text text NOT NULL DEFAULT '',
  seo_text text NOT NULL DEFAULT '',
  is_active boolean NOT NULL DEFAULT true,
  sort_order integer NOT NULL DEFAULT 0,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now()
);

ALTER TABLE public.seo_locations ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can read active seo_locations"
  ON public.seo_locations
  FOR SELECT
  USING (true);

INSERT INTO public.seo_locations (slug, location_name, h1, seo_title, seo_description, intro_text, seo_text, sort_order) VALUES
('tehosmotr-bezhickiy-rayon', 'Бежицкий район', 'Техосмотр в Бежицком районе Брянска', 'Техосмотр Бежицкий район Брянск — официальный пункт техосмотра', 'Пройдите техосмотр в Бежицком районе Брянска. Диагностическая карта, официальное оформление, запись онлайн.', 'Жители Бежицкого района могут пройти техосмотр быстро и официально в нашем аккредитованном пункте. Удобный подъезд, минимальное время ожидания.', 'Техосмотр в Бежицком районе Брянска — это удобная услуга для владельцев легковых автомобилей, грузовиков, автобусов и прицепов. Наш пункт технического осмотра расположен по адресу: Брянск, Большое Полпино, ул. Лермонтова, 1Б — всего 15–20 минут езды из центра Бежицкого района. Мы проводим техосмотр для ОСАГО всех категорий транспортных средств: M1, M2, M3, N1, N2, N3, O1–O4, L. Диагностическая карта оформляется в электронном виде и моментально передаётся в базу ЕАИСТО. Стоимость техосмотра в Бежицком районе Брянска зависит от категории транспорта и утверждена региональным постановлением. Записаться можно онлайн или по телефону. Мы работаем без выходных, чтобы вам было максимально удобно. Пройти техосмотр в Бежицком районе — значит получить официальный документ без очередей и переплат. Наш пункт аккредитован РСА, что гарантирует легитимность диагностической карты для оформления полиса ОСАГО.', 1),

('tehosmotr-volodarskiy-rayon', 'Володарский район', 'Техосмотр в Володарском районе Брянска', 'Техосмотр Володарский район Брянск — запись онлайн', 'Официальный техосмотр в Володарском районе Брянска. Все категории транспорта, доступные цены, запись онлайн.', 'Из Володарского района до нашего пункта техосмотра — 10–15 минут на автомобиле. Официальное оформление диагностической карты для ОСАГО.', 'Техосмотр в Володарском районе Брянска доступен для всех категорий транспортных средств. Наш аккредитованный пункт расположен в Большом Полпино, что позволяет жителям Володарского района добраться за 10–15 минут. Мы проводим полный технический осмотр в соответствии с требованиями законодательства РФ. Диагностическая карта для Володарского района оформляется в электронном формате и сразу попадает в единую базу ЕАИСТО. Цены на техосмотр утверждены постановлением Правительства Брянской области. Записаться на техосмотр из Володарского района можно через онлайн-форму на сайте или по телефону. Мы принимаем легковые автомобили, грузовики, автобусы, мотоциклы и прицепы. Пройти техосмотр для ОСАГО в Володарском районе — это просто, быстро и официально.', 2),

('tehosmotr-sovetskiy-rayon', 'Советский район', 'Техосмотр в Советском районе Брянска', 'Техосмотр Советский район Брянск — диагностическая карта для ОСАГО', 'Техосмотр в Советском районе Брянска. Диагностическая карта для ОСАГО, все категории ТС, доступные цены.', 'Для жителей Советского района — удобный маршрут до пункта техосмотра. Официальная диагностическая карта за 20 минут.', 'Техосмотр для жителей Советского района Брянска — это быстрая и удобная процедура в нашем официальном пункте. Советский район — центральная часть Брянска, откуда до нашего пункта в Большом Полпино можно доехать за 20 минут. Мы принимаем все категории транспортных средств: легковые (M1), грузовые (N1–N3), автобусы (M2, M3), мотоциклы (L) и прицепы (O1–O4). Диагностическая карта для Советского района оформляется электронно и мгновенно появляется в базе ЕАИСТО. Стоимость техосмотра в Советском районе соответствует региональным тарифам. Пройти техосмотр для ОСАГО из Советского района Брянска можно по предварительной записи — онлайн или по телефону. Наш пункт аккредитован РСА и работает по графику, удобному для автовладельцев.', 3),

('tehosmotr-fokinskiy-rayon', 'Фокинский район', 'Техосмотр в Фокинском районе Брянска', 'Техосмотр Фокинский район Брянск — официальный пункт, запись онлайн', 'Пройдите техосмотр в Фокинском районе Брянска. Официальный пункт, диагностическая карта, запись онлайн.', 'Жителям Фокинского района — кратчайший путь до пункта техосмотра. Запись онлайн, без очередей.', 'Техосмотр в Фокинском районе Брянска — это возможность пройти официальный технический осмотр в аккредитованном пункте всего в 15 минутах езды. Фокинский район расположен рядом с Большим Полпино, что делает наш пункт максимально доступным для его жителей. Мы проводим техосмотр для ОСАГО для всех категорий: легковые, грузовые, автобусы, мотоциклы, прицепы. Диагностическая карта для Фокинского района оформляется в электронном виде и передаётся в ЕАИСТО. Цены на техосмотр в Фокинском районе утверждены региональным постановлением. Записаться можно через сайт или по телефону. Пройти техосмотр в Фокинском районе Брянска — быстро, официально и без переплат.', 4),

('tehosmotr-bolshoe-polpino', 'Большое Полпино', 'Техосмотр в Большом Полпино', 'Техосмотр Большое Полпино — официальный пункт техосмотра', 'Пройдите техосмотр в Большом Полпино. Диагностическая карта для ОСАГО, удобная запись, официальное оформление.', 'Наш пункт техосмотра находится непосредственно в Большом Полпино. Приезжайте без лишних поездок по городу!', 'Техосмотр в Большом Полпино — это максимально удобный вариант для местных жителей и тех, кто работает в промзоне. Пункт техосмотра расположен по адресу: ул. Лермонтова, 1Б. Мы проводим технический осмотр для всех категорий транспортных средств: легковые автомобили, грузовики, автобусы, мотоциклы и прицепы. Диагностическая карта в Большом Полпино оформляется электронно и моментально попадает в базу ЕАИСТО. Стоимость техосмотра соответствует региональным тарифам. Пройти техосмотр для ОСАГО в Большом Полпино можно по записи через сайт или по телефону. Наш пункт аккредитован РСА и работает ежедневно. Техосмотр в Большом Полпино — это ваш ближайший и самый быстрый вариант.', 5),

('punkt-tehosmotra-bryansk', 'Пункт техосмотра Брянск', 'Пункт техосмотра в Брянске', 'Пункт техосмотра Брянск — адрес, телефон, график работы', 'Пункт техосмотра в Брянске: адрес, телефон, график. Все категории ТС, диагностическая карта для ОСАГО.', 'Официальный аккредитованный пункт технического осмотра в Брянске. Адрес: Большое Полпино, ул. Лермонтова, 1Б.', 'Пункт техосмотра в Брянске расположен по адресу: Большое Полпино, ул. Лермонтова, 1Б. Наш пункт аккредитован Российским союзом автостраховщиков (РСА) и уполномочен выдавать диагностические карты для оформления полиса ОСАГО. Мы обслуживаем все категории транспортных средств: легковые автомобили (M1), грузовые (N1–N3), автобусы (M2, M3), мотоциклы и мопеды (L), прицепы и полуприцепы (O1–O4). Пункт техосмотра в Брянске работает ежедневно. Записаться можно онлайн через сайт или по телефону. Стоимость технического осмотра определена постановлением Правительства Брянской области. Диагностическая карта оформляется в электронном виде и сразу передаётся в единую систему ЕАИСТО.', 6),

('tehosmotr-dlya-osago-bryansk', 'Техосмотр для ОСАГО Брянск', 'Техосмотр для ОСАГО в Брянске', 'Техосмотр для ОСАГО Брянск — диагностическая карта, запись онлайн', 'Техосмотр для ОСАГО в Брянске. Диагностическая карта для страховки, все категории ТС, официальный пункт.', 'Диагностическая карта для ОСАГО — обязательный документ для оформления страховки. Пройдите техосмотр в нашем аккредитованном пункте.', 'Техосмотр для ОСАГО в Брянске — обязательная процедура для оформления полиса обязательного страхования. Диагностическая карта подтверждает техническую исправность автомобиля и является условием для покупки ОСАГО. Наш пункт техосмотра в Брянске аккредитован РСА и уполномочен проводить техосмотр для ОСАГО всех категорий транспорта. Диагностическая карта для ОСАГО оформляется электронно и мгновенно передаётся в базу ЕАИСТО. Стоимость техосмотра для ОСАГО в Брянске утверждена региональным постановлением. Записаться на техосмотр для ОСАГО можно через сайт или по телефону. Мы работаем без выходных и принимаем без очередей по предварительной записи.', 7);
